mapper.select:
SELECT id, type, title, summary, content, cover_url, link_url, author, source_org, is_top, status, sort_order, publish_time, create_time, update_time, creator_id FROM cms_content
AND type = #{type}
AND status = #{status}
AND ( title LIKE CONCAT('%', #{keyWords}, '%') OR summary LIKE CONCAT('%', #{keyWords}, '%') )
AND source_org = #{org_id}
AND publish_time >= CONCAT(#{startTime}, ' 00:00:00')
AND publish_time < DATE_ADD(CONCAT(#{endTime}, ' 00:00:00'), INTERVAL 1 DAY)
ORDER BY is_top DESC, sort_order DESC,
publish_time ASC
publish_time DESC

mapper.insert:
INSERT INTO cms_content (
    type, title, summary, content, cover_url, link_url,
    author, source_org, is_top, status, sort_order,
    publish_time, create_time, update_time, creator_id
) VALUES (
    #{type}, #{title}, #{summary}, #{content}, #{coverUrl}, #{linkUrl},
    #{author}, #{sourceOrg}, #{isTop}, #{status}, #{sortOrder},
    #{publishTime}, NOW(), NOW(), #{creatorId}
)
